{"code": "import json
import pandas as pd

# Get businesses with parking attributes
businesses_with_parking = var_functions.query_db:25

# Filter for those that have BusinessParking or BikeParking=True
eligible_businesses = []
for business in businesses_with_parking:
    has_business_parking = False
    has_bike_parking = False

    # Check if attributes exist and is not None
    if business.get('attributes'):
        attributes = business['attributes']

        # Check for BusinessParking (exists and not empty)
        if 'BusinessParking' in attributes and attributes['BusinessParking']:
            # Check if it's a dict with any True values or a non-empty string
            business_parking_val = attributes['BusinessParking']
            if isinstance(business_parking_val, dict):
                # Check if any parking type is True
                if any(business_parking_val.values()):
                    has_business_parking = True
            elif isinstance(business_parking_val, str):
                # For string values, check if it contains True
                if 'True' in business_parking_val:
                    has_business_parking = True

        # Check for BikeParking=True
        if 'BikeParking' in attributes:
            bike_parking_val = attributes['BikeParking']
            if bike_parking_val == 'True' or bike_parking_val == True:
                has_bike_parking = True

    # If has either business parking or bike parking
    if has_business_parking or has_bike_parking:
        eligible_businesses.append({
            'business_id': business['business_id'],
            'name': business.get('name', ''),
            'has_business_parking': has_business_parking,
            'has_bike_parking': has_bike_parking
        })

# Count the eligible businesses
count = len(eligible_businesses)

print('__RESULT__:')
print(json.dumps({
    'count': count,
    'businesses': eligible_businesses
}))"}

